def _snowflake_semantic_fact_to_nested(
    snowflake_semantic_fact: SnowflakeSemanticFact,
) -> SnowflakeSemanticFactNested:
    """Convert flat SnowflakeSemanticFact to nested format."""
    attrs = SnowflakeSemanticFactAttributes()
    _populate_snowflake_semantic_fact_attrs(attrs, snowflake_semantic_fact)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        snowflake_semantic_fact,
        _SNOWFLAKE_SEMANTIC_FACT_REL_FIELDS,
        SnowflakeSemanticFactRelationshipAttributes,
    )
    return SnowflakeSemanticFactNested(
        guid=snowflake_semantic_fact.guid,
        type_name=snowflake_semantic_fact.type_name,
        status=snowflake_semantic_fact.status,
        version=snowflake_semantic_fact.version,
        create_time=snowflake_semantic_fact.create_time,
        update_time=snowflake_semantic_fact.update_time,
        created_by=snowflake_semantic_fact.created_by,
        updated_by=snowflake_semantic_fact.updated_by,
        classifications=snowflake_semantic_fact.classifications,
        classification_names=snowflake_semantic_fact.classification_names,
        meanings=snowflake_semantic_fact.meanings,
        labels=snowflake_semantic_fact.labels,
        business_attributes=snowflake_semantic_fact.business_attributes,
        custom_attributes=snowflake_semantic_fact.custom_attributes,
        pending_tasks=snowflake_semantic_fact.pending_tasks,
        proxy=snowflake_semantic_fact.proxy,
        is_incomplete=snowflake_semantic_fact.is_incomplete,
        provenance_type=snowflake_semantic_fact.provenance_type,
        home_id=snowflake_semantic_fact.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _snowflake_semantic_fact_from_nested(
    nested: SnowflakeSemanticFactNested,
) -> SnowflakeSemanticFact:
    """Convert nested format to flat SnowflakeSemanticFact."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SnowflakeSemanticFactAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SNOWFLAKE_SEMANTIC_FACT_REL_FIELDS,
        SnowflakeSemanticFactRelationshipAttributes,
    )
    return SnowflakeSemanticFact(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_snowflake_semantic_fact_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _snowflake_semantic_fact_to_nested_bytes(
    snowflake_semantic_fact: SnowflakeSemanticFact, serde: Serde
) -> bytes:
    """Convert flat SnowflakeSemanticFact to nested JSON bytes."""
    return serde.encode(_snowflake_semantic_fact_to_nested(snowflake_semantic_fact))


def _snowflake_semantic_fact_from_nested_bytes(
    data: bytes, serde: Serde
) -> SnowflakeSemanticFact:
    """Convert nested JSON bytes to flat SnowflakeSemanticFact."""
    nested = serde.decode(data, SnowflakeSemanticFactNested)
    return _snowflake_semantic_fact_from_nested(nested)


